func readDepsFile(path string) ([]dep, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer f.Close()

	var out []dep
	sc := bufio.NewScanner(f)
	ln := 0
	for sc.Scan() {
		ln++
		line := strings.TrimSpace(sc.Text())
		if line == "" || strings.HasPrefix(line, "#") || strings.HasPrefix(line, "//") {
			continue
		}
		d, err := parseDepLine(line)
		if err != nil {
			return nil, fmt.Errorf("%s:%d: %w", path, ln, err)
		}
		out = append(out, d)
	}
	if err := sc.Err(); err != nil {
		return nil, err
	}
	return out, nil
}

func parseDepsArgs(args []string) ([]dep, error) {
	var out []dep
	for _, a := range args {
		a = strings.TrimSpace(a)
		if a == "" {
			continue
		}
		d, err := parseDepLine(a)
		if err != nil {
			return nil, err
		}
		out = append(out, d)
	}
	return out, nil
}

// Supported formats:
//   github.com/org/repo@v1.2.3
//   internal:git.corp.local/team/repo
//   git.corp.local/team/repo internal
//   git.corp.local/team/repo;internal
func parseDepLine(line string) (dep, error) {
	line = strings.TrimSpace(line)
	if line == "" {
		return dep{}, errors.New("empty dependency")
	}

	d := dep{}

	if strings.HasPrefix(line, "internal:") {
		d.Internal = true
		d.Path = strings.TrimSpace(strings.TrimPrefix(line, "internal:"))
		if d.Path == "" {
			return dep{}, errors.New("missing path after internal:")
		}
		return d, nil
	}

	parts := splitFieldsSemicolon(line)
	if len(parts) == 0 {
		return dep{}, errors.New("invalid dependency line")
	}
	d.Path = parts[0]
	for _, p := range parts[1:] {
		if strings.EqualFold(p, "internal") {
			d.Internal = true
		}
	}
	if d.Path == "" {
		return dep{}, errors.New("missing dependency path")
	}
	return d, nil
}

func splitFieldsSemicolon(s string) []string {
	s = strings.TrimSpace(s)
	if s == "" {
		return nil
	}
	var fields []string
	semi := strings.Split(s, ";")
	for _, seg := range semi {
		for _, f := range strings.Fields(strings.TrimSpace(seg)) {
			if f != "" {
				fields = append(fields, f)
			}
		}
	}
	return fields
}

func run(bin string, args []string, env []string, dir string) error {
	cmd := exec.Command(bin, args...)
	cmd.Env = env
	cmd.Dir = dir
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	cmd.Stdin = os.Stdin

	// On Windows, ensure we find go.exe if "go" was provided.
	if runtime.GOOS == "windows" && (bin == "go" || strings.EqualFold(bin, "go.exe")) {
		// Let exec resolve via PATH; no-op.
	}

	return cmd.Run()
}

func upsertEnv(env []string, key, val string) []string {
	prefix := key + "="
	for i := range env {
		if strings.HasPrefix(env[i], prefix) {
			env[i] = prefix + val
			return env
		}
	}
	return append(env, prefix+val)
}

func upsertEnvIfMissing(env []string, key, val string) []string {
	prefix := key + "="
	for i := range env {
		if strings.HasPrefix(env[i], prefix) {
			return env
		}
	}
	return append(env, prefix+val)
}

func cmdString(bin string, args []string, env []string, dir string) string {
	var b bytes.Buffer
	b.WriteString("DIR=")
	b.WriteString(shellQuote(dir))
	b.WriteString(" ")

	for _, k := range []string{"GOPRIVATE", "GOSUMDB", "GONOSUMDB", "GONOPROXY"} {
		if v, ok := lookupEnv(env, k); ok {
			b.WriteString(k)
			b.WriteString("=")
			b.WriteString(shellQuote(v))
			b.WriteString(" ")
		}
	}

	b.WriteString(shellQuote(bin))
	for _, a := range args {
		b.WriteString(" ")
		b.WriteString(shellQuote(a))
	}
	return b.String()
}

func lookupEnv(env []string, key string) (string, bool) {
	prefix := key + "="
	for _, e := range env {
		if strings.HasPrefix(e, prefix) {
			return strings.TrimPrefix(e, prefix), true
		}
	}
	return "", false
}

func shellQuote(s string) string {
	if s == "" {
		return "''"
	}
	if runtime.GOOS == "windows" {
		// Minimal quoting for display only.
		if strings.ContainsAny(s, " \t\"") {
			return `"` + strings.ReplaceAll(s, `"`, `\"`) + `"`
		}
		return s
	}
	if strings.ContainsAny(s, " \t\n'\"\\$`") {
		return "'" + strings.ReplaceAll(s, "'", `'\''`) + "'"
	}
	return s
}

func exitIf(err error) {
	if err == nil {
		return
	}
	fmt.Fprintln(os.Stderr, "error:", err)
	os.Exit(1)
}